ngle keyword in isolation.', NULL, 'Expression of Ideas', 'Rhetorical Synthesis', 'reading_writing', 'expression', 'SYN', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"hard_content_v2","original":true,"explanation_v2":true,"hard_content_v2":true}'::jsonb, now(), now())
